using McpHttpServer.Tools;
using ModelContextProtocol;
using ModelContextProtocol.Server;
using System.ComponentModel;

var builder = WebApplication.CreateBuilder(args);

builder.Services
    .AddMcpServer()
    .WithHttpTransport()
    .WithToolsFromAssembly()
    .WithResources();

var app = builder.Build();

// Health check endpoint (non-MCP)
app.MapGet("/health", () => "OK");

// Mount the MCP endpoint at /mcp using Streamable HTTP transport
app.MapMcp();

app.Run();

// --- Resource providers ---

[McpServerResourceType]
public class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        Description = "Returns the current application configuration.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            environment = "production",
            version = "1.0.0",
            features = new { darkMode = true, betaAccess = false },
            maxConnections = 100
        };
        return System.Text.Json.JsonSerializer.Serialize(config, new System.Text.Json.JsonSerializerOptions
        {
            WriteIndented = true
        });
    }

    [McpServerResource(
        UriTemplate = "config://app/status",
        Name = "Server Status",
        Description = "Returns current server status information.")]
    public static string GetServerStatus()
    {
        var status = new
        {
            uptime = Environment.TickCount64 / 1000,
            timestamp = DateTime.UtcNow,
            machineName = Environment.MachineName,
            processorCount = Environment.ProcessorCount
        };
        return System.Text.Json.JsonSerializer.Serialize(status, new System.Text.Json.JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

