            timestamp = DateTime.UtcNow,
            machineName = Environment.MachineName,
            processorCount = Environment.ProcessorCount
        };
        return System.Text.Json.JsonSerializer.Serialize(status, new System.Text.Json.JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

