1. using McpHttpServer.Tools;
2. using ModelContextProtocol;
3. using ModelContextProtocol.Server;
4. using System.ComponentModel;
5. 
6. var builder = WebApplication.CreateBuilder(args);
7. 
8. builder.Services
9.     .AddMcpServer()
10.     .WithHttpTransport()
11.     .WithToolsFromAssembly()
12.     .WithResources<ConfigResource>();
13. 
14. var app = builder.Build();
15. 
16. // Health check endpoint (non-MCP)
17. app.MapGet("/health", () => "OK");
18. 
19. // Mount the MCP endpoint at /mcp using Streamable HTTP transport
20. app.MapMcp();
21. 
22. app.Run();
23. 
24. // --- Resource providers ---
25. 
26. [McpServerResourceType]
27. public class ConfigResource
28. {
29.     [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings")]
30.     [Description("Returns the current application configuration.")]
31.     public static string GetAppSettings()
32.     {
33.         var config = new
34.         {
35.             environment = "production",
36.             version = "1.0.0",
37.             features = new { darkMode = true, betaAccess = false },
38.             maxConnections = 100
39.         };
40.         return System.Text.Json.JsonSerializer.Serialize(config, new System.Text.Json.JsonSerializerOptions
41.         {
42.             WriteIndented = true
43.         });
44.     }
45. 
46.     [McpServerResource(UriTemplate = "config://app/status", Name = "Server Status")]
47.     [Description("Returns current server status information.")]
48.     public static string GetServerStatus()
49.     {
50.         var status = new
51.         {
52.             uptime = Environment.TickCount64 / 1000,
53.             timestamp = DateTime.UtcNow,
54.             machineName = Environment.MachineName,
55.             processorCount = Environment.ProcessorCount
56.         };
57.         return System.Text.Json.JsonSerializer.Serialize(status, new System.Text.Json.JsonSerializerOptions
58.         {
59.             WriteIndented = true
60.         });
61.     }
62. }
63.

